// Backup generates a json file from a slice of all LinkAnchoredPathDB instances in the backrepo
func (backRepoLinkAnchoredPath *BackRepoLinkAnchoredPathStruct) Backup(dirPath string) {

	filename := filepath.Join(dirPath, "LinkAnchoredPathDB.json")

	// organize the map into an array with increasing IDs, in order to have repoductible
	// backup file
	forBackup := make([]*LinkAnchoredPathDB, 0)
	for _, linkanchoredpathDB := range backRepoLinkAnchoredPath.Map_LinkAnchoredPathDBID_LinkAnchoredPathDB {
		forBackup = append(forBackup, linkanchoredpathDB)
	}

	sort.Slice(forBackup[:], func(i, j int) bool {
		return forBackup[i].ID < forBackup[j].ID
	})

	file, err := json.MarshalIndent(forBackup, "", " ")

	if err != nil {
		log.Fatal("Cannot json LinkAnchoredPath ", filename, " ", err.Error())
	}

	err = ioutil.WriteFile(filename, file, 0644)
	if err != nil {
		log.Fatal("Cannot write the json LinkAnchoredPath file", err.Error())
	}
}

