// RestorePhaseOne read the file "LinkAnchoredPathDB.json" in dirPath that stores an array
// of LinkAnchoredPathDB and stores it in the database
// the map BackRepoLinkAnchoredPathid_atBckpTime_newID is updated accordingly
func (backRepoLinkAnchoredPath *BackRepoLinkAnchoredPathStruct) RestorePhaseOne(dirPath string) {

	// resets the map
	BackRepoLinkAnchoredPathid_atBckpTime_newID = make(map[uint]uint)

	filename := filepath.Join(dirPath, "LinkAnchoredPathDB.json")
	jsonFile, err := os.Open(filename)
	// if we os.Open returns an error then handle it
	if err != nil {
		log.Fatal("Cannot restore/open the json LinkAnchoredPath file", filename, " ", err.Error())
	}

	// read our opened jsonFile as a byte array.
	byteValue, _ := ioutil.ReadAll(jsonFile)

	var forRestore []*LinkAnchoredPathDB

	err = json.Unmarshal(byteValue, &forRestore)

	// fill up Map_LinkAnchoredPathDBID_LinkAnchoredPathDB
	for _, linkanchoredpathDB := range forRestore {

		linkanchoredpathDB_ID_atBackupTime := linkanchoredpathDB.ID
		linkanchoredpathDB.ID = 0
		_, err := backRepoLinkAnchoredPath.db.Create(linkanchoredpathDB)
		if err != nil {
			log.Fatal(err)
		}
		backRepoLinkAnchoredPath.Map_LinkAnchoredPathDBID_LinkAnchoredPathDB[linkanchoredpathDB.ID] = linkanchoredpathDB
		BackRepoLinkAnchoredPathid_atBckpTime_newID[linkanchoredpathDB_ID_atBackupTime] = linkanchoredpathDB.ID
	}

	if err != nil {
		log.Fatal("Cannot restore/unmarshall json LinkAnchoredPath file", err.Error())
	}
}

